/**
 * Organization Module Types
 *
 * Type definitions for the Organization module including:
 * - Organization entity types
 * - CRUD DTOs
 * - Settings types
 * - Event payloads
 * - Query filters
 *
 * @module modules/_core/organization/types
 *
 * @example
 * ```typescript
 * import type {
 *   Organization,
 *   CreateOrganizationRequest,
 *   OrganizationSettings,
 * } from '@/modules/_core/organization/organization.types';
 *
 * async function createOrg(data: CreateOrganizationRequest): Promise<Organization> { ... }
 * ```
 */

import type { OrganizationStatus } from '@prisma/client';

// -----------------------------------------------------------------------------
// Core Entity Types
// -----------------------------------------------------------------------------

/**
 * Organization entity from Prisma
 */
export interface Organization {
  /** Unique identifier (CUID) */
  id: string;
  /** Organization name */
  name: string;
  /** URL-friendly slug (unique) */
  slug: string;
  /** Contact email */
  email: string;
  /** Contact phone (optional) */
  phone: string | null;
  /** Logo URL (optional) */
  logo: string | null;
  /** Organization settings (JSON) */
  settings: OrganizationSettings;
  /** Current status */
  status: OrganizationStatus;
  /** Subscription plan ID */
  planId: string | null;
  /** Trial end date */
  trialEndsAt: Date | null;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
  /** Soft delete timestamp */
  deletedAt: Date | null;
}

/**
 * Organization with related data
 */
export interface OrganizationWithRelations extends Organization {
  /** Associated subscription plan */
  plan?: {
    id: string;
    name: string;
    tier: string;
  } | null;
  /** User count */
  _count?: {
    users: number;
    menus: number;
    orders: number;
  };
}

// -----------------------------------------------------------------------------
// Settings Types
// -----------------------------------------------------------------------------

/**
 * Organization settings structure
 */
export interface OrganizationSettings {
  /** Business Information */
  business?: BusinessSettings;
  /** Localization settings */
  localization?: LocalizationSettings;
  /** Feature toggles */
  features?: FeatureSettings;
  /** Notification preferences */
  notifications?: NotificationSettings;
  /** Branding/appearance */
  branding?: BrandingSettings;
}

/**
 * Business-related settings
 */
export interface BusinessSettings {
  /** Legal business name */
  legalName?: string;
  /** Tax identification number */
  taxId?: string;
  /** Business address */
  address?: AddressInfo;
  /** Business type/category */
  businessType?: string;
  /** Operating hours */
  operatingHours?: OperatingHours;
}

/**
 * Address information
 */
export interface AddressInfo {
  /** Street address line 1 */
  street1?: string;
  /** Street address line 2 */
  street2?: string;
  /** City */
  city?: string;
  /** State/Province */
  state?: string;
  /** Postal/ZIP code */
  postalCode?: string;
  /** Country code (ISO 3166-1 alpha-2) */
  country?: string;
}

/**
 * Operating hours for each day
 */
export interface OperatingHours {
  monday?: DayHours;
  tuesday?: DayHours;
  wednesday?: DayHours;
  thursday?: DayHours;
  friday?: DayHours;
  saturday?: DayHours;
  sunday?: DayHours;
}

/**
 * Hours for a single day
 */
export interface DayHours {
  /** Whether the business is open */
  isOpen: boolean;
  /** Opening time (HH:mm format) */
  open?: string;
  /** Closing time (HH:mm format) */
  close?: string;
  /** Break times */
  breaks?: Array<{ start: string; end: string }>;
}

/**
 * Localization settings
 */
export interface LocalizationSettings {
  /** Primary language code */
  language?: string;
  /** Timezone (IANA format) */
  timezone?: string;
  /** Currency code (ISO 4217) */
  currency?: string;
  /** Date format preference */
  dateFormat?: string;
  /** Time format (12h or 24h) */
  timeFormat?: '12h' | '24h';
}

/**
 * Feature toggle settings
 */
export interface FeatureSettings {
  /** Enable online ordering */
  enableOnlineOrdering?: boolean;
  /** Enable table reservations */
  enableReservations?: boolean;
  /** Enable customer reviews */
  enableReviews?: boolean;
  /** Enable AI-powered features */
  enableAIFeatures?: boolean;
  /** Enable multi-language menu */
  enableMultiLanguage?: boolean;
  /** Enable allergen information */
  enableAllergenInfo?: boolean;
  /** Enable nutrition information */
  enableNutritionInfo?: boolean;
}

/**
 * Notification settings
 */
export interface NotificationSettings {
  /** Email notifications for new orders */
  emailOnNewOrder?: boolean;
  /** SMS notifications for new orders */
  smsOnNewOrder?: boolean;
  /** Push notifications enabled */
  pushEnabled?: boolean;
  /** Daily summary email */
  dailySummaryEmail?: boolean;
  /** Weekly analytics report */
  weeklyReportEmail?: boolean;
}

/**
 * Branding settings
 */
export interface BrandingSettings {
  /** Primary brand color (hex) */
  primaryColor?: string;
  /** Secondary brand color (hex) */
  secondaryColor?: string;
  /** Custom font family */
  fontFamily?: string;
  /** Favicon URL */
  favicon?: string;
  /** Custom CSS (premium feature) */
  customCss?: string;
}

// -----------------------------------------------------------------------------
// Request/Response Types
// -----------------------------------------------------------------------------

/**
 * Create organization request
 */
export interface CreateOrganizationRequest {
  /** Organization name */
  name: string;
  /** URL-friendly slug (auto-generated if not provided) */
  slug?: string;
  /** Contact email */
  email: string;
  /** Contact phone (optional) */
  phone?: string;
  /** Initial settings (optional) */
  settings?: Partial<OrganizationSettings>;
}

/**
 * Create organization response
 */
export interface CreateOrganizationResponse {
  /** Created organization */
  organization: Organization;
  /** Success message */
  message: string;
}

/**
 * Update organization request
 */
export interface UpdateOrganizationRequest {
  /** Organization name */
  name?: string;
  /** URL-friendly slug */
  slug?: string;
  /** Contact email */
  email?: string;
  /** Contact phone */
  phone?: string | null;
  /** Logo URL */
  logo?: string | null;
}

/**
 * Update organization response
 */
export interface UpdateOrganizationResponse {
  /** Updated organization */
  organization: Organization;
  /** Success message */
  message: string;
}

/**
 * Update organization settings request
 */
export interface UpdateSettingsRequest {
  /** Settings to update (merged with existing) */
  settings: Partial<OrganizationSettings>;
}

/**
 * Update organization settings response
 */
export interface UpdateSettingsResponse {
  /** Updated settings */
  settings: OrganizationSettings;
  /** Success message */
  message: string;
}

/**
 * Change organization status request
 */
export interface ChangeStatusRequest {
  /** New status */
  status: OrganizationStatus;
  /** Reason for status change (for audit) */
  reason?: string;
}

/**
 * Change organization status response
 */
export interface ChangeStatusResponse {
  /** Updated organization */
  organization: Organization;
  /** Previous status */
  previousStatus: OrganizationStatus;
  /** Success message */
  message: string;
}

/**
 * Organization summary for listings
 */
export interface OrganizationSummary {
  /** Organization ID */
  id: string;
  /** Organization name */
  name: string;
  /** URL slug */
  slug: string;
  /** Logo URL */
  logo: string | null;
  /** Current status */
  status: OrganizationStatus;
  /** Plan name */
  planName?: string;
  /** User count */
  userCount?: number;
  /** Creation date */
  createdAt: Date;
}

// -----------------------------------------------------------------------------
// Query/Filter Types
// -----------------------------------------------------------------------------

/**
 * Organization list query filters
 */
export interface OrganizationListFilters {
  /** Filter by status */
  status?: OrganizationStatus;
  /** Filter by plan ID */
  planId?: string;
  /** Search by name or email */
  search?: string;
  /** Filter by creation date range */
  createdAfter?: Date;
  createdBefore?: Date;
  /** Include soft-deleted */
  includeDeleted?: boolean;
}

/**
 * Organization list query params
 */
export interface OrganizationListParams extends OrganizationListFilters {
  /** Page number (1-indexed) */
  page?: number;
  /** Items per page */
  perPage?: number;
  /** Sort field */
  sortBy?: 'name' | 'createdAt' | 'status';
  /** Sort direction */
  sortOrder?: 'asc' | 'desc';
}

// -----------------------------------------------------------------------------
// Event Payload Types
// -----------------------------------------------------------------------------

/**
 * Organization created event payload
 */
export interface OrganizationCreatedEvent {
  /** Organization ID */
  organizationId: string;
  /** Organization name */
  name: string;
  /** Organization slug */
  slug: string;
  /** Creator user ID (if applicable) */
  createdBy?: string;
  /** Event timestamp */
  timestamp: string;
}

/**
 * Organization updated event payload
 */
export interface OrganizationUpdatedEvent {
  /** Organization ID */
  organizationId: string;
  /** Changed fields */
  changes: Partial<Organization>;
  /** User who made the change */
  updatedBy?: string;
  /** Event timestamp */
  timestamp: string;
}

/**
 * Organization deleted event payload
 */
export interface OrganizationDeletedEvent {
  /** Organization ID */
  organizationId: string;
  /** Organization name (for reference) */
  name: string;
  /** User who deleted */
  deletedBy?: string;
  /** Event timestamp */
  timestamp: string;
}

/**
 * Organization settings updated event payload
 */
export interface OrganizationSettingsUpdatedEvent {
  /** Organization ID */
  organizationId: string;
  /** Previous settings */
  previousSettings: OrganizationSettings;
  /** New settings */
  newSettings: OrganizationSettings;
  /** User who made the change */
  updatedBy?: string;
  /** Event timestamp */
  timestamp: string;
}

/**
 * Organization status changed event payload
 */
export interface OrganizationStatusChangedEvent {
  /** Organization ID */
  organizationId: string;
  /** Previous status */
  previousStatus: OrganizationStatus;
  /** New status */
  newStatus: OrganizationStatus;
  /** Reason for change */
  reason?: string;
  /** User who made the change */
  changedBy?: string;
  /** Event timestamp */
  timestamp: string;
}

// -----------------------------------------------------------------------------
// Hook Context Types
// -----------------------------------------------------------------------------

/**
 * Before create hook context
 */
export interface BeforeCreateContext {
  /** Create request data */
  data: CreateOrganizationRequest;
  /** User creating the organization */
  userId?: string;
}

/**
 * After create hook context
 */
export interface AfterCreateContext {
  /** Created organization */
  organization: Organization;
  /** User who created the organization */
  userId?: string;
}

/**
 * Before update hook context
 */
export interface BeforeUpdateContext {
  /** Organization ID */
  organizationId: string;
  /** Update request data */
  data: UpdateOrganizationRequest;
  /** User making the update */
  userId?: string;
}

/**
 * After update hook context
 */
export interface AfterUpdateContext {
  /** Updated organization */
  organization: Organization;
  /** Previous values */
  previousData: Organization;
  /** User who made the update */
  userId?: string;
}

// -----------------------------------------------------------------------------
// Module Settings Types
// -----------------------------------------------------------------------------

/**
 * Organization module settings
 */
export interface OrganizationModuleSettings {
  /** Default timezone for new organizations */
  defaultTimezone: string;
  /** Default currency for new organizations */
  defaultCurrency: string;
  /** Default language for new organizations */
  defaultLanguage: string;
  /** Allow public organization registration */
  allowPublicRegistration: boolean;
  /** Require email verification for org creation */
  requireEmailVerification: boolean;
  /** Maximum users per organization */
  maxUsersPerOrg: number;
  /** Maximum branches per organization */
  maxBranchesPerOrg: number;
}

// -----------------------------------------------------------------------------
// Type Guards
// -----------------------------------------------------------------------------

/**
 * Type guard to check if an object is a valid Organization
 */
export function isOrganization(obj: unknown): obj is Organization {
  return (
    typeof obj === 'object' &&
    obj !== null &&
    'id' in obj &&
    'name' in obj &&
    'slug' in obj &&
    'email' in obj &&
    'status' in obj
  );
}

/**
 * Type guard to check if settings is a valid OrganizationSettings
 */
export function isOrganizationSettings(obj: unknown): obj is OrganizationSettings {
  if (typeof obj !== 'object' || obj === null) {
    return false;
  }
  // Empty object is valid settings
  if (Object.keys(obj).length === 0) {
    return true;
  }
  // Check known keys
  const knownKeys = ['business', 'localization', 'features', 'notifications', 'branding'];
  return Object.keys(obj).every((key) => knownKeys.includes(key));
}
